import{_ as e,o as r,c as a,a2 as d}from"./chunks/framework.c3r8iWL8.js";const g=JSON.parse('{"title":"Guide: Planning, ADR & Specs","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/planning-adr-specs.md","filePath":"guides/planning-adr-specs.md","lastUpdated":1782929962000}'),o={name:"guides/planning-adr-specs.md"};function n(s,t,i,c,l,p){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-planning-adr-specs" tabindex="-1">Guide: Planning, ADR &amp; Specs <a class="header-anchor" href="#guide-planning-adr-specs" aria-label="Permalink to &quot;Guide: Planning, ADR &amp; Specs&quot;">​</a></h1><p><strong>Decision:</strong> How should AI participate in planning, and where do ADRs and specs live?</p><p>Related: <a href="./../planning-and-adr.html">planning-and-adr.md</a> · <a href="./../sops/SOP-002-adr-lifecycle.html">SOP-002</a> · <a href="./../sops/SOP-003-spec-approval.html">SOP-003</a></p><hr><h2 id="decisions-in-this-space" tabindex="-1">Decisions in this space <a class="header-anchor" href="#decisions-in-this-space" aria-label="Permalink to &quot;Decisions in this space&quot;">​</a></h2><ol><li>ADR format and location</li><li>When AI drafts ADRs vs humans only</li><li>Spec-first vs code-first with retroactive specs</li><li>How non-production artifacts are shared</li></ol><hr><h2 id="adr-format-location" tabindex="-1">ADR format &amp; location <a class="header-anchor" href="#adr-format-location" aria-label="Permalink to &quot;ADR format &amp; location&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Git <code>docs/adr/</code> (MADR)</strong></td><td>Versioned, PR review, close to code</td><td>Non-devs may not browse Git</td></tr><tr><td><strong>Confluence / wiki</strong></td><td>Familiar to PMs</td><td>Stale copies; hard for agents to index reliably</td></tr><tr><td><strong>Backstage TechDocs only</strong></td><td>Great discovery</td><td>Still needs Git source for truth</td></tr><tr><td><strong>Issue tracker only</strong></td><td>Fast</td><td>Not durable architecture memory</td></tr></tbody></table><p><strong>Recommended:</strong> Git canonical + Backstage/portal for discovery + optional Confluence mirror.</p><hr><h2 id="ai-in-adr-drafting" tabindex="-1">AI in ADR drafting <a class="header-anchor" href="#ai-in-adr-drafting" aria-label="Permalink to &quot;AI in ADR drafting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>AI drafts, architect accepts</strong></td><td>Speed; consistent structure</td><td>Architect may rubber-stamp without reading</td></tr><tr><td><strong>Human-only ADRs</strong></td><td>Maximum accountability</td><td>Slow; inconsistent quality</td></tr><tr><td><strong>AI drafts options only, human writes decision</strong></td><td>Balanced</td><td>Two-step friction</td></tr></tbody></table><p><strong>Recommended:</strong> AI drafts with status <code>proposed</code>; architect <strong>must</strong> set <code>accepted</code>. Never index Proposed ADRs for coding agents.</p><hr><h2 id="spec-first-vs-code-first" tabindex="-1">Spec-first vs code-first <a class="header-anchor" href="#spec-first-vs-code-first" aria-label="Permalink to &quot;Spec-first vs code-first&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Spec-first (OpenAPI approved before impl)</strong></td><td>AI codegen bounded; contract tests meaningful</td><td>Upfront latency for small fixes</td></tr><tr><td><strong>Code-first, spec after</strong></td><td>Fast spikes</td><td>AI invents APIs; contract tests lag</td></tr><tr><td><strong>Hybrid (spec for public APIs only)</strong></td><td>Pragmatic</td><td>Two tracks confuse teams</td></tr></tbody></table><p><strong>Recommended:</strong> Spec-first for any API surface or cross-team boundary; spikes allowed with time-box and ADR if pattern sticks.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>ADR theater</strong></td><td>Long ADRs nobody reads</td><td>One decision per ADR; link from specs</td></tr><tr><td><strong>Rubber-stamp AI ADRs</strong></td><td>Wrong architecture at scale</td><td>Architect must edit or reject; ARB for cross-team</td></tr><tr><td><strong>Proposed ADRs in agent index</strong></td><td>Agents treat draft as law</td><td>Index only <code>accepted</code></td></tr><tr><td><strong>Spec and code diverge</strong></td><td>CI green but wrong behavior</td><td>Contract tests from OpenAPI; block merge if spec stale</td></tr><tr><td><strong>Wiki as source of truth</strong></td><td>Agents retrieve outdated text</td><td>Git canonical; wiki is mirror</td></tr><tr><td><strong>No link spec ↔ ADR</strong></td><td>Traceability lost</td><td><code>x-adr</code> on OpenAPI operations</td></tr><tr><td><strong>Planning AI without existing ADR context</strong></td><td>Repeated contradictory decisions</td><td>RAG over Accepted ADRs before draft</td></tr><tr><td><strong>Skipping threat model on AI-generated design</strong></td><td>Security gaps in generated APIs</td><td>SEC review gate for external / T1</td></tr></tbody></table><hr><h2 id="suggested-starting-point" tabindex="-1">Suggested starting point <a class="header-anchor" href="#suggested-starting-point" aria-label="Permalink to &quot;Suggested starting point&quot;">​</a></h2><ol><li>MADR in Git with statuses: <code>proposed</code> → <code>accepted</code> | <code>rejected</code> | <code>superseded</code></li><li>OpenAPI 3.1 with <code>x-status: approved</code> before implementation</li><li>Planning agent retrieves Accepted ADRs before drafting</li><li>Publish pipeline described in <a href="./knowledge-indexing-portals.html">knowledge-indexing-portals.md</a></li></ol><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./spec-driven-development.html">Spec-driven development</a></li><li><a href="./knowledge-indexing-portals.html">Knowledge indexing &amp; portals</a></li></ul>',27)])])}const f=e(o,[["render",n]]);export{g as __pageData,f as default};
